insert into anki.quiz_questions (id, category, question, answer, distractors, difficulty) values ('147a7265-9ade-24bf-c9b3-bdcacc456044', 'vue', 'Какой watch-вариант нужен, чтобы глубоко отслеживать вложенные изменения reactive-объекта?', 'watch с { deep: true } (или сам reactive-источник)', '["watchEffect всегда глубокий","watch без опций глубокий","computed с deep"]'::jsonb, 2) on conflict (id) do nothing;
